        parts := strings.Split(arg, ",")
        if len(parts) != 2 {
                return
        }
        dx, _ := strconv.Atoi(parts[0])
        dy, _ := strconv.Atoi(parts[1])
        nx, ny := w.PlayerX+dx, w.PlayerY+dy
        if w.InBounds(nx, ny) && !w.IsWall(nx, ny) {
